// @ts-nocheck
// Reason: Convex types are not generated locally until a Convex project is linked.
"use client";

import { motion, AnimatePresence } from "framer-motion";
import { DialogueBlock } from "@workspace/ui/components/DialogueBlock";
import { Doc } from "@/../convex/_generated/dataModel";

interface StorySceneRendererProps {
  scene: Doc<"scenes"> | null;
}

export function StorySceneRenderer({ scene }: StorySceneRendererProps) {
  if (!scene) {
    return (
      <div className="flex h-full w-full items-center justify-center p-12">
        <div className="animate-pulse bg-muted h-64 w-64 rounded-xl" />
      </div>
    );
  }

  return (
    <AnimatePresence mode="wait">
      <motion.div
        key={scene._id}
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        exit={{ opacity: 0, y: -20 }}
        transition={{ duration: 0.6, ease: "easeOut" }}
        className="mx-auto flex max-w-3xl flex-col gap-8 pb-32 pt-16"
      >
        {scene.blocks.map((block, idx) => {
          if (block.type === "text") {
            return (
              <p
                key={idx}
                className="text-lg leading-loose text-foreground/90 font-serif"
              >
                {block.content}
              </p>
            );
          }
          if (block.type === "image") {
            return (
              <figure key={idx} className="my-8 flex flex-col items-center gap-3">
                <img
                  src={block.url}
                  alt={block.caption || "Scene illustration"}
                  className="rounded-2xl border border-border/50 object-cover shadow-xl max-h-[60vh] w-full bg-muted"
                  loading="lazy"
                />
                {block.caption && (
                  <figcaption className="text-sm font-medium text-muted-foreground italic">
                    {block.caption}
                  </figcaption>
                )}
              </figure>
            );
          }
          if (block.type === "dialogue") {
            return (
              <DialogueBlock
                key={idx}
                characterName={block.character}
                avatarUrl={block.avatarUrl}
                quote={<p>{block.quote}</p>}
                align={idx % 2 === 0 ? "left" : "right"} 
              />
            );
          }
          return null;
        })}
      </motion.div>
    </AnimatePresence>
  );
}
